// Collect unique dataset IDs from steps that have one
const steps = $input.all().map(i => i.json);
const datasetIds = [...new Set(steps.filter(s => s.dataset_id).map(s => s.dataset_id))];

// Build view names: v_ds_<id with hyphens replaced by underscores>
const viewNames = datasetIds.map(id => 'v_ds_' + id.replace(/-/g, '_'));

// Build SQL IN list (safely quoted)
const viewNamesSql = viewNames.length > 0
  ? viewNames.map(v => "'" + v.replace(/'/g, "''") + "'").join(', ')
  : "'__no_views__'";

return [{ json: { view_names_sql: viewNamesSql, dataset_ids: datasetIds, view_names: viewNames } }];

const steps = $('Fetch Step Results').all().map(i => i.json);
const cols = $input.all().map(i => i.json);

// Group columns by view name
const viewColumns = {};
for (const c of cols) {
  if (!viewColumns[c.table_name]) viewColumns[c.table_name] = [];
  viewColumns[c.table_name].push(`${c.column_name} (${c.data_type})`);
}

// Build step context: for each step, show purpose, temp table, and view columns
const safeReportId = $('Webhook').first().json.body.report_id.replace(/[^a-zA-Z0-9_]/g, '_');

const stepLines = steps.map(s => {
  const viewName = s.dataset_id ? 'v_ds_' + s.dataset_id.replace(/-/g, '_') : null;
  const colList = viewName && viewColumns[viewName]
    ? viewColumns[viewName].join(', ')
    : (s.dataset_id ? 'columns unavailable' : 'aggregate step — no direct dataset');
  const tempTable = s.raw_table_name
    ? `n8n_data."${s.raw_table_name}"`
    : (s.dataset_id ? `n8n_data."tmp_${safeReportId}_step_${s.step_number}"` : 'none');
  return [
    `Step ${s.step_number}: ${s.purpose}`,
    `  Dataset ID  : ${s.dataset_id || 'none (aggregate step)'}`,
    `  Dataset view: ${viewName ? `n8n_data.${viewName}` : 'none'}`,
    `  Temp table  : ${tempTable}`,
    `  View columns: ${colList}`,
  ].join('\n');
}).join('\n\n');

const reportHtml = $('Webhook').first().json.body.report_html || '';
const validationPrompt = $('Webhook').first().json.body.validation_prompt || '';

return [{
  json: {
    step_context: stepLines,
    report_html: reportHtml,
    validation_prompt: validationPrompt,
  }
}];

